#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        char X[101], Y[101];
        scanf("%s %s", X, Y);
        int ok = 1;
        for(int i=0; X[i] && Y[i]; ++i){
            if(X[i]!='?' && Y[i]!='?' && X[i]!=Y[i]){ ok=0; break; }
        }
        printf("%s\n", ok?"Yes":"No");
    }
    return 0;
}

